import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import MedicalDisclaimer from "@/components/MedicalDisclaimer";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is GFR?", a: "GFR, or glomerular filtration rate, estimates how well your kidneys filter waste from the blood." },
  { q: "How is eGFR calculated?", a: "eGFR is estimated from serum creatinine, age, and sex using equations such as CKD-EPI." },
  { q: "What is a normal GFR?", a: "A GFR of 90 or higher is often considered normal when there are no other signs of kidney damage." },
  { q: "What does a low GFR mean?", a: "A low GFR can indicate reduced kidney function and should be discussed with a healthcare professional." },
  { q: "How do you improve GFR?", a: "Kidney health support can include blood pressure control, blood sugar control, hydration, medication review, and medical follow-up." },
];

const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
function egfr(age: number, gender: string, creatinine: number) {
  const female = gender === "Female";
  const k = female ? 0.7 : 0.9;
  const alpha = female ? -0.241 : -0.302;
  return 142 * Math.pow(Math.min(creatinine / k, 1), alpha) * Math.pow(Math.max(creatinine / k, 1), -1.2) * Math.pow(0.9938, age) * (female ? 1.012 : 1);
}
function stage(gfr: number) {
  if (gfr >= 90) return ["G1", "Normal or high", "90-100%", "Monitor if other kidney damage signs exist"];
  if (gfr >= 60) return ["G2", "Mildly decreased", "60-89%", "Discuss trends with clinician"];
  if (gfr >= 45) return ["G3a", "Mild to moderate decrease", "45-59%", "Medical follow-up recommended"];
  if (gfr >= 30) return ["G3b", "Moderate to severe decrease", "30-44%", "Kidney care planning"];
  if (gfr >= 15) return ["G4", "Severely decreased", "15-29%", "Specialist care is important"];
  return ["G5", "Kidney failure range", "Under 15%", "Urgent medical care"];
}

export default function GFRCalculator() {
  const [age, setAge] = useState(45);
  const [gender, setGender] = useState("Male");
  const [race, setRace] = useState("Not used in 2021 CKD-EPI");
  const [creatinine, setCreatinine] = useState(1);
  const result = useMemo(() => { const value = egfr(age, gender, creatinine); return { value, stage: stage(value) }; }, [age, gender, creatinine]);
  const rows = [["G1", "90 or higher", "Normal or high", "90-100%", "Monitor if other signs"], ["G2", "60-89", "Mildly decreased", "60-89%", "Track with clinician"], ["G3a", "45-59", "Mild to moderate decrease", "45-59%", "Medical follow-up"], ["G3b", "30-44", "Moderate to severe decrease", "30-44%", "Kidney care planning"], ["G4", "15-29", "Severely decreased", "15-29%", "Specialist care"], ["G5", "Under 15", "Kidney failure range", "Under 15%", "Urgent medical care"]];
  return (
    <>
      <SEOHead title="Free GFR Calculator Online - Calculate Kidney Function and eGFR Instantly | CalcHive" description="Free online GFR calculator. Calculate estimated glomerular filtration rate (eGFR) using the CKD-EPI equation and determine kidney function stage instantly. 100% free, no signup required." canonical="/gfr-calculator" keywords="free GFR calculator, eGFR calculator free online, kidney function calculator free, CKD-EPI calculator free, glomerular filtration rate calculator free online" category="Health Calculators" breadcrumbName="Free GFR Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10"><div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-teal-600 dark:text-teal-400 bg-teal-50 dark:bg-teal-950/50 px-3 py-1 rounded-full mb-4 inline-block">Health</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free GFR Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate kidney function using the CKD-EPI creatinine equation and see the kidney function stage.</p></div><AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8"><div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold block mb-2">Age</label><input type="number" value={age} onChange={(e) => setAge(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold block mb-2">Gender</label><select value={gender} onChange={(e) => setGender(e.target.value)} className={inputClass}><option>Male</option><option>Female</option></select></div><div><label className="text-sm font-semibold block mb-2">Race</label><select value={race} onChange={(e) => setRace(e.target.value)} className={inputClass}><option>Not used in 2021 CKD-EPI</option><option>Black</option><option>Non-Black</option></select></div><div><label className="text-sm font-semibold block mb-2">Serum creatinine (mg/dL)</label><input type="number" value={creatinine} onChange={(e) => setCreatinine(Number(e.target.value))} className={inputClass} /></div></div><div className="bg-gradient-to-br from-teal-500 to-teal-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Estimated eGFR</p><p className="text-5xl sm:text-6xl font-black text-white">{result.value.toFixed(1)}</p><p className="text-white/80 text-sm">mL/min/1.73m2</p></div><div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Stage</p><p className="text-lg font-extrabold">{result.stage[0]}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Meaning</p><p className="text-lg font-extrabold">{result.stage[1]}</p></div></div></section><MedicalDisclaimer variant="gfr" /><ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold">How to Calculate Your eGFR and Kidney Function for Free</h2><p className="text-muted-foreground leading-relaxed">The CKD-EPI creatinine equation estimates filtration from age, sex, and serum creatinine. This is an educational estimate, not a diagnosis.</p><h2 className="text-2xl font-bold">What Your GFR Result Means for Kidney Health</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold mb-3">Kidney Function Stages by GFR</caption><thead className="bg-muted/60"><tr>{["Stage", "GFR Range", "Description", "Kidney Function %", "Action Needed"].map((h) => <th key={h} className="text-left py-3 px-3">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((r) => <tr key={r[0]}>{r.map((c) => <td key={c} className="py-2.5 px-3">{c}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold">Free Kidney Function eGFR Calculator for Everyone</h2></section>
        <section className="mb-8"><h3 className="text-xl font-bold mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section><AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/gfr-calculator" headingLevel="h3" /></main>
    </>
  );
}


